INSERT INTO public.managed_email_types (email_key, category, name, description, default_subject, default_body_html, available_variables, trigger_event, is_system, is_active)
VALUES
  ('support_chat_assigned', 'support', 'Support Chat Assigned', 'Email sent to agent when a support chat is assigned to them', 'New Support Chat Assigned: {{subject}}', '<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px"><h2 style="color:#1a1a1a">New Chat Assigned to You</h2><p style="color:#555;font-size:14px">Hi {{agent_name}},</p><p style="color:#555;font-size:14px">A support conversation has been assigned to you.</p><div style="background:#f5f5f5;border-radius:8px;padding:16px;margin:16px 0"><p style="margin:4px 0;font-size:14px"><strong>Subject:</strong> {{subject}}</p><p style="margin:4px 0;font-size:14px"><strong>Channel:</strong> {{channel}}</p></div><p style="color:#555;font-size:14px">Please log in to the admin dashboard to respond.</p><p style="color:#999;font-size:12px;margin-top:24px">— Kang Open Banking Support</p></div>', '["agent_name","subject","channel"]', 'chat_assigned_to_agent', true, true),
  ('support_chat_resolved', 'support', 'Support Chat Resolved', 'Email sent to user when their support chat is resolved or closed', 'Your Support Request Has Been {{status}}: {{subject}}', '<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px"><h2 style="color:#1a1a1a">Support Request {{status}}</h2><p style="color:#555;font-size:14px">Hi {{user_name}},</p><p style="color:#555;font-size:14px">Your support conversation <strong>"{{subject}}"</strong> has been marked as <strong>{{status}}</strong>.</p><p style="color:#555;font-size:14px">If you need further assistance, feel free to start a new conversation anytime.</p><p style="color:#999;font-size:12px;margin-top:24px">— Kang Open Banking Support</p></div>', '["user_name","subject","status"]', 'chat_resolved_or_closed', true, true)
